          <StatCard icon={Shield} label="管理员" value={formatNumber(stats.admin_users)} detail="具备后台权限" tone="gold" />
          <StatCard icon={Activity} label="文献总量" value={formatNumber(stats.total_papers)} detail="含回收站中的文献" tone="slate" />
