import { useCallback, useEffect, useState } from 'react'
import { getStoredAuthToken } from '../services/authApi'

const ANNOTATIONS_BASE = '/api/papers'

async function apiFetch(url, options = {}) {
  const token = getStoredAuthToken()
  const headers = { ...options.headers }
  if (token) headers.Authorization = `Bearer ${token}`

  const resp = await fetch(url, { ...options, headers })
  if (!resp.ok) {
    let detail = '请求失败'
    try {
      const data = await resp.json()
      if (typeof data?.detail === 'string') detail = data.detail
    } catch {
      // Keep the default message.
    }
    throw new Error(detail)
  }

  return resp.status === 204 ? null : resp.json()
}

export function useAnnotations(paperId) {
  const [annotations, setAnnotations] = useState([])
  const [loading, setLoading] = useState(false)

  const loadAnnotations = useCallback(async () => {
    if (!paperId) {
      setAnnotations([])
      return
    }

    setLoading(true)
    try {
      const data = await apiFetch(`${ANNOTATIONS_BASE}/${paperId}/annotations`)
      setAnnotations(data?.annotations || [])
    } catch {
      // Annotation loading should not block opening the PDF.
    } finally {
      setLoading(false)
    }
  }, [paperId])

  const createAnnotation = useCallback(async ({
    pageNumber,
    startChar,
    endChar,
    quoteText,
    rects,
    type,
    color,
    source = 'native',
    geometryVersion = 'v2',
  }) => {
    if (!paperId) return null

    try {
      const data = await apiFetch(`${ANNOTATIONS_BASE}/${paperId}/annotations`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          page_number: pageNumber,
          start_char: startChar,
          end_char: endChar,
          quote_text: quoteText,
          rects: rects || [],
          type,
          color,
          source,
          geometry_version: geometryVersion,
        }),
      })
      if (data) setAnnotations((prev) => [...prev, data])
      return data
    } catch {
      return null
    }
  }, [paperId])

  const eraseAnnotationRange = useCallback(async ({ pageNumber, startChar, endChar }) => {
    if (!paperId) return null

    try {
      const data = await apiFetch(`${ANNOTATIONS_BASE}/${paperId}/annotations/erase`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          page_number: pageNumber,
          start_char: startChar,
          end_char: endChar,
        }),
      })
      if (data?.annotations) setAnnotations(data.annotations)
      return data
    } catch {
      return null
    }
  }, [paperId])

  const restoreAnnotations = useCallback(async (snapshot = []) => {
    if (!paperId) return null

    try {
      const data = await apiFetch(`${ANNOTATIONS_BASE}/${paperId}/annotations/restore`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ annotations: snapshot }),
      })
      if (data?.annotations) setAnnotations(data.annotations)
      return data
    } catch {
      return null
    }
  }, [paperId])

  const deleteAnnotation = useCallback(async (annotationId) => {
    if (!paperId) return null

    try {
      await apiFetch(`${ANNOTATIONS_BASE}/${paperId}/annotations/${annotationId}`, { method: 'DELETE' })
      setAnnotations((prev) => prev.filter((annotation) => annotation.id !== annotationId))
      return true
    } catch {
      return null
    }
  }, [paperId])

  const clearAnnotations = useCallback(async () => {
    if (!paperId) return null

    try {
      const data = await apiFetch(`${ANNOTATIONS_BASE}/${paperId}/annotations`, { method: 'DELETE' })
      setAnnotations(data?.annotations || [])
      return data
    } catch {
      return null
    }
  }, [paperId])

  useEffect(() => {
    loadAnnotations()
  }, [loadAnnotations])

  return {
    annotations,
    loading,
    loadAnnotations,
    createAnnotation,
    deleteAnnotation,
    clearAnnotations,
    eraseAnnotationRange,
    restoreAnnotations,
  }
}

import { useCallback, useEffect, useState } from 'react'
import { getStoredAuthToken } from '../services/authApi'

const INK_BASE = '/api/papers'

async function apiFetch(url, options = {}) {
  const token = getStoredAuthToken()
  const headers = { ...options.headers }
  if (token) headers.Authorization = `Bearer ${token}`

  const resp = await fetch(url, { ...options, headers })
  if (!resp.ok) {
    let detail = '请求失败'
    try {
      const data = await resp.json()
      if (typeof data?.detail === 'string') detail = data.detail
    } catch {
      // Keep the default message.
    }
    throw new Error(detail)
  }

  return resp.status === 204 ? null : resp.json()
}

export function useInkAnnotations(paperId) {
  const [inkAnnotations, setInkAnnotations] = useState([])
  const [loading, setLoading] = useState(false)

  const loadInkAnnotations = useCallback(async () => {
    if (!paperId) {
      setInkAnnotations([])
      return
    }

    setLoading(true)
    try {
      const data = await apiFetch(`${INK_BASE}/${paperId}/ink-annotations`)
      setInkAnnotations(data?.ink_annotations || [])
    } catch {
      setInkAnnotations([])
    } finally {
      setLoading(false)
    }
  }, [paperId])

  const createInkAnnotation = useCallback(async ({
    pageNumber,
    color,
    opacity,
    strokeWidth,
    points,
  }) => {
    if (!paperId || !points?.length) return null

    const temporaryId = `pending:${Date.now()}:${Math.random().toString(36).slice(2)}`
    const optimistic = {
      id: temporaryId,
      page_number: pageNumber,
      color,
      opacity,
      stroke_width: strokeWidth,
      points,
      pending: true,
    }
    setInkAnnotations((prev) => [...prev, optimistic])

    try {
      const data = await apiFetch(`${INK_BASE}/${paperId}/ink-annotations`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          page_number: pageNumber,
          color,
          opacity,
          stroke_width: strokeWidth,
          points,
        }),
      })
      if (data) {
        setInkAnnotations((prev) => prev.map((item) => item.id === temporaryId ? data : item))
      }
      return data
    } catch {
      setInkAnnotations((prev) => prev.map((item) =>
        item.id === temporaryId ? { ...item, pending: false, unsynced: true } : item,
      ))
      return null
    }
  }, [paperId])

  const deleteInkAnnotation = useCallback(async (inkId) => {
    if (!paperId || inkId == null) return null

    const snapshot = inkAnnotations
    setInkAnnotations((prev) => prev.filter((item) => item.id !== inkId))

    if (String(inkId).startsWith('pending:')) {
      return true
    }

    try {
      await apiFetch(`${INK_BASE}/${paperId}/ink-annotations/${inkId}`, { method: 'DELETE' })
      return true
    } catch {
      setInkAnnotations(snapshot)
      return null
    }
  }, [inkAnnotations, paperId])

  useEffect(() => {
    loadInkAnnotations()
  }, [loadInkAnnotations])

  return {
    inkAnnotations,
    loading,
    loadInkAnnotations,
    createInkAnnotation,
    deleteInkAnnotation,
  }
}

import { useCallback, useEffect, useState } from 'react'
import { createNotebookFromTemplate } from '../components/reader/noteTree'
import { getStoredAuthToken } from '../services/authApi'

async function apiFetch(url, options = {}) {
  const token = getStoredAuthToken()
  const headers = { ...options.headers }
  if (token) headers.Authorization = `Bearer ${token}`

  const response = await fetch(url, { ...options, headers })
  if (!response.ok) {
    let detail = 'Request failed'
    try {
      const payload = await response.json()
      if (typeof payload?.detail === 'string') detail = payload.detail
    } catch {
      // ignore
    }
    throw new Error(detail)
  }

  return response.status === 204 ? null : response.json()
}

export function usePaperNotes(paperId) {
  const [notebooks, setNotebooks] = useState([])
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)

  const loadNotebooks = useCallback(async () => {
    if (!paperId) {
      setNotebooks([])
      return
    }

    setLoading(true)
    try {
      const data = await apiFetch(`/api/papers/${paperId}/notebooks`)
      setNotebooks(data?.notebooks || [])
    } catch {
      setNotebooks([])
    } finally {
      setLoading(false)
    }
  }, [paperId])

  const saveNotebooks = useCallback(async (draftNotebooks) => {
    if (!paperId) return null
    setSaving(true)
    try {
      const data = await apiFetch(`/api/papers/${paperId}/notebooks/save`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notebooks: draftNotebooks || [] }),
      })
      setNotebooks(data?.notebooks || [])
      return data?.notebooks || []
    } catch {
      return null
    } finally {
      setSaving(false)
    }
  }, [paperId])

  const createNotebookDraft = useCallback((kind = 'blank') => {
    setNotebooks((previous) => {
      const sortOrder = previous.length
      const notebook = createNotebookFromTemplate(kind, sortOrder)
      return [...previous, notebook]
    })
  }, [])

  useEffect(() => {
    loadNotebooks()
  }, [loadNotebooks])

  return {
    notebooks,
    loading,
    saving,
    setNotebooks,
    loadNotebooks,
    saveNotebooks,
    createNotebookDraft,
  }
}

