  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M5 12h14" />
      <path d="m12 5 7 7-7 7" />
    </svg>
  )
}

function EyeIcon({ hidden = false }) {
  if (hidden) {
    return (
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <path d="M3 3l18 18" />
        <path d="M10.6 10.7a2 2 0 0 0 2.7 2.7" />
        <path d="M9.4 5.2A9.7 9.7 0 0 1 12 5c5 0 8.5 4.1 9.6 5.6a2.3 2.3 0 0 1 0 2.8 18.4 18.4 0 0 1-2.3 2.5" />
        <path d="M6.1 6.7a18.9 18.9 0 0 0-3.7 3.9 2.3 2.3 0 0 0 0 2.8C3.5 14.9 7 19 12 19a9.6 9.6 0 0 0 4.3-1" />
      </svg>
    )
  }

  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path d="M2.062 12.348a1 1 0 0 1 0-.696 10.75 10.75 0 0 1 19.876 0 1 1 0 0 1 0 .696 10.75 10.75 0 0 1-19.876 0" />
      <circle cx="12" cy="12" r="3" />
    </svg>
  )
}

function CaptchaPanel({
  captcha,
  value,
  isLoading,
  onChange,
  onRefresh,
  onFocus,
  onBlur,
}) {
  return (
    <div className="auth-form__field">
      <label htmlFor="captcha-code">验证码</label>
      <div className="auth-captcha">
        <button
          type="button"
          className="auth-captcha__image"
          onClick={onRefresh}
          disabled={isLoading}
          aria-label="刷新验证码"
        >
          {captcha?.image_data_url ? (
            <img src={captcha.image_data_url} alt="图形验证码" />
          ) : (
            <span>加载中...</span>
          )}
        </button>
        <div className="auth-captcha__controls">
          <input
            id="captcha-code"
            type="text"
            placeholder="请输入图形验证码"
            autoComplete="off"
            inputMode="text"
            maxLength={8}
            value={value}
            onChange={(event) => onChange(event.target.value.toUpperCase())}
            onFocus={onFocus}
            onBlur={onBlur}
            className="auth-input"
          />
          <button
            type="button"
            className="auth-captcha__refresh"
            onClick={onRefresh}
            disabled={isLoading}
          >
            <RefreshCw />
            <span>换一张</span>
          </button>
        </div>
      </div>
    </div>
  )
}

function VerificationCodeField({
  className = '',
  id,
  label,
  placeholder,
  value,
  onChange,
  onSend,
  sending,
  cooldown,
  disabled = false,
  required = false,
}) {
  return (
    <div className={`auth-form__field ${className}`.trim()}>
      <label htmlFor={id}>
        {label}
        {required ? ' *' : ''}
      </label>
      <div className="auth-captcha__controls">
        <input
          id={id}
          type="text"
          inputMode="numeric"
          maxLength={6}
          placeholder={placeholder}
          value={value}
          onChange={(event) => onChange(event.target.value.replace(/\D/g, '').slice(0, 6))}
          className="auth-input"
          disabled={disabled}
        />
        <button
          type="button"
          className="auth-captcha__refresh"
          onClick={onSend}
          disabled={disabled || sending || cooldown > 0}
        >
          <span>{sending ? '发送中...' : cooldown > 0 ? `${cooldown}s` : '发送验证码'}</span>
        </button>
      </div>
    </div>
  )
}

function SendCodeCaptchaModal({
  open,
  title,
  captcha,
  codeValue,
  isLoading,
  isSubmitting,
  onChange,
  onRefresh,
  onClose,
  onConfirm,
}) {
  if (!open) return null

  return (
    <div className="auth-modal-backdrop" role="dialog" aria-modal="true" aria-label={title}>
      <div className="auth-modal">
        <div className="auth-modal__header">
          <strong>{title}</strong>
          <button type="button" className="text-link" onClick={onClose}>
            关闭
          </button>
        </div>

        <CaptchaPanel
          captcha={captcha}
          value={codeValue}
          isLoading={isLoading}
          onChange={onChange}
          onRefresh={onRefresh}
        />

        <div className="auth-modal__actions">
          <button type="button" className="auth-captcha__refresh" onClick={onClose}>
            取消
          </button>
          <button
            type="button"
            className="auth-captcha__refresh auth-captcha__refresh--primary"
            onClick={onConfirm}
            disabled={isSubmitting}
          >
            {isSubmitting ? '发送中...' : '确认发送'}
          </button>
        </div>
      </div>
    </div>
  )
}

function InteractiveHoverButton({ text, icon, className = '', type = 'button', ...props }) {
  return (
    <button
      className={`hover-button ${className}`.trim()}
      type={type}
      {...props}
    >
      <span className="hover-button__text">{text}</span>
      <span className="hover-button__overlay">
        <span>{text}</span>
        {icon || <ArrowIcon />}
      </span>
    </button>
  )
}

function buildEmptyForm() {
  return {
    account: '',
    phone: '',
    phoneVerificationCode: '',
    email: '',
    emailVerificationCode: '',
    resetVerificationCode: '',
    password: '',
    confirmPassword: '',
    captchaCode: '',
    nickname: '',
    education: EDUCATION_OPTIONS[1],
    occupation: OCCUPATION_OPTIONS[0],
    organization: '',
    discipline: DISCIPLINE_OPTIONS[0],
    agreeTerms: false,
  }
}

function isValidPhone(value) {
  return /^1[3-9]\d{9}$/.test(value.trim())
}

function isValidEmail(value) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim())
}

function Login({ initialMode = 'login', onAuthSuccess }) {
  const [mode, setMode] = useState(initialMode)
  const [signupStep, setSignupStep] = useState(1)
  const [loginStep, setLoginStep] = useState('login')
  const [form, setForm] = useState(buildEmptyForm)
  const [showPassword, setShowPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [isTyping, setIsTyping] = useState(false)
  const [activeFieldGroup, setActiveFieldGroup] = useState('default')
  const [activePasswordField, setActivePasswordField] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState('')
  const [captcha, setCaptcha] = useState(null)
  const [isCaptchaLoading, setIsCaptchaLoading] = useState(false)
  const [isSendingPhoneCode, setIsSendingPhoneCode] = useState(false)
  const [isSendingEmailCode, setIsSendingEmailCode] = useState(false)
  const [isSendingResetCode, setIsSendingResetCode] = useState(false)
  const [sendCodeModal, setSendCodeModal] = useState({ open: false, channel: '' })
  const [sendCodeCaptcha, setSendCodeCaptcha] = useState(null)
  const [sendCodeCaptchaValue, setSendCodeCaptchaValue] = useState('')
  const [isSendCodeCaptchaLoading, setIsSendCodeCaptchaLoading] = useState(false)
  const [phoneCodeCooldown, setPhoneCodeCooldown] = useState(0)
  const [emailCodeCooldown, setEmailCodeCooldown] = useState(0)
  const [resetCodeCooldown, setResetCodeCooldown] = useState(0)
  const current = copy[mode]

  const passwordLength = useMemo(() => {
    if (mode === 'login') {
      return form.password.length
    }
    return Math.max(form.password.length, form.confirmPassword.length)
  }, [form.confirmPassword.length, form.password.length, mode])

  function updateField(field, value) {
    setForm((currentForm) => ({
      ...currentForm,
      [field]: value,
    }))
  }

  function handleFieldFocus(group, field = '') {
    setActiveFieldGroup(group)
    setActivePasswordField(group === 'password' ? field : '')
    setIsTyping(group !== 'agreement')
  }

  function handleFieldBlur() {
    setActiveFieldGroup('default')
    setActivePasswordField('')
    setIsTyping(false)
  }

  function resetForMode(nextMode) {
    setMode(nextMode)
    setSignupStep(1)
    setLoginStep('login')
    setForm(buildEmptyForm())
    setShowPassword(false)
    setShowConfirmPassword(false)
    setIsTyping(false)
    setActiveFieldGroup('default')
    setActivePasswordField('')
    setIsLoading(false)
    setError('')
  }

  async function loadCaptcha(scene = mode) {
    setIsCaptchaLoading(true)
    try {
      const payload = await fetchCaptchaChallenge(scene)
      setCaptcha(payload)
      setForm((currentForm) => ({
        ...currentForm,
        captchaCode: '',
      }))
    } catch {
      setCaptcha(null)
    } finally {
      setIsCaptchaLoading(false)
    }
  }

  async function loadSendCodeCaptcha(scene = 'register') {
    setIsSendCodeCaptchaLoading(true)
    try {
      const payload = await fetchCaptchaChallenge(scene)
      setSendCodeCaptcha(payload)
      setSendCodeCaptchaValue('')
    } catch {
      setSendCodeCaptcha(null)
    } finally {
      setIsSendCodeCaptchaLoading(false)
    }
  }

  useEffect(() => {
    loadCaptcha(mode)
  }, [mode])

  useEffect(() => {
    if (phoneCodeCooldown <= 0) return undefined
    const timer = window.setTimeout(() => {
      setPhoneCodeCooldown((value) => Math.max(0, value - 1))
    }, 1000)
    return () => window.clearTimeout(timer)
  }, [phoneCodeCooldown])

  useEffect(() => {
    if (emailCodeCooldown <= 0) return undefined
    const timer = window.setTimeout(() => {
      setEmailCodeCooldown((value) => Math.max(0, value - 1))
    }, 1000)
    return () => window.clearTimeout(timer)
  }, [emailCodeCooldown])

  useEffect(() => {
    if (resetCodeCooldown <= 0) return undefined
    const timer = window.setTimeout(() => {
      setResetCodeCooldown((value) => Math.max(0, value - 1))
    }, 1000)
    return () => window.clearTimeout(timer)
  }, [resetCodeCooldown])

  function validateLogin() {
    if (!form.account.trim()) {
      return '请输入手机号或邮箱。'
    }
    if (form.password.length < 8) {
      return '密码至少需要 8 位。'
    }
    if (!captcha?.challenge_id) {
      return '验证码加载失败，请刷新后重试。'
    }
    if (form.captchaCode.trim().length < 4) {
      return '请输入验证码。'
    }
    return ''
  }

  function validateResetRequest() {
    if (!form.account.trim()) {
      return '请输入手机号或邮箱。'
    }
    if (!captcha?.challenge_id) {
      return '验证码加载失败，请刷新后重试。'
    }
    if (form.captchaCode.trim().length < 4) {
      return '请输入图形验证码。'
    }
    return ''
  }

  function validateResetSubmit() {
    const requestError = validateResetRequest()
    if (requestError) return requestError
    if (form.resetVerificationCode.trim().length !== 6) {
      return '请输入 6 位重置验证码。'
    }
    if (form.password.length < 8) {
      return '新密码至少需要 8 位。'
    }
    if (form.password !== form.confirmPassword) {
      return '两次输入的新密码不一致。'
    }
    return ''
  }

  function validateSignupStepOne() {
    if (!isValidPhone(form.phone)) {
      return '请输入正确的手机号。'
    }
    if (form.email.trim() && !isValidEmail(form.email)) {
      return '邮箱填写后必须是正确格式。'
    }
    if (form.password.length < 8) {
      return '密码至少需要 8 位。'
    }
    if (form.password !== form.confirmPassword) {
      return '两次输入的密码不一致。'
    }
    if (form.phoneVerificationCode.trim().length !== 6) {
      return '请输入 6 位短信验证码。'
    }
    if (form.email.trim() && form.emailVerificationCode.trim().length !== 6) {
      return '填写邮箱后必须输入 6 位邮箱验证码。'
    }
    return ''
  }

  async function openSendCodeModal(channel) {
    setError('')

    if (channel === 'sms') {
      if (!isValidPhone(form.phone)) {
        setError('请先输入正确的手机号。')
        return
      }
    } else {
      if (!form.email.trim()) {
        setError('请先填写邮箱。')
        return
      }
      if (!isValidEmail(form.email)) {
        setError('请输入正确的邮箱地址。')
        return
      }
    }

    setSendCodeModal({ open: true, channel })
    await loadSendCodeCaptcha('register')
  }

  async function handleSendVerificationCode() {
    const channel = sendCodeModal.channel
    if (!channel) return
    setError('')

    if (!sendCodeCaptcha?.challenge_id) {
      setError('验证码加载失败，请刷新后重试。')
      return
    }

    if (sendCodeCaptchaValue.trim().length < 4) {
      setError('请输入图形验证码。')
      return
    }

    if (channel === 'sms') {
      setIsSendingPhoneCode(true)
    } else {
      setIsSendingEmailCode(true)
    }

    try {
      const payload = await sendRegisterVerificationCode({
        channel,
        target: channel === 'sms' ? form.phone.trim() : form.email.trim(),
        captcha_id: sendCodeCaptcha.challenge_id,
        captcha_code: sendCodeCaptchaValue.trim(),
      })
      if (channel === 'sms') {
        setPhoneCodeCooldown(Number(payload?.cooldown_seconds) || 60)
      } else {
        setEmailCodeCooldown(Number(payload?.cooldown_seconds) || 60)
      }
      setSendCodeModal({ open: false, channel: '' })
      setSendCodeCaptcha(null)
      setSendCodeCaptchaValue('')
    } catch (requestError) {
      setError(requestError instanceof Error ? requestError.message : '验证码发送失败，请稍后再试。')
      await loadSendCodeCaptcha('register')
    } finally {
      if (channel === 'sms') {
        setIsSendingPhoneCode(false)
      } else {
        setIsSendingEmailCode(false)
      }
    }
  }

  async function handleSendResetCode() {
    setError('')
    const validationError = validateResetRequest()
    if (validationError) {
      setError(validationError)
      return
    }

    setIsSendingResetCode(true)
    try {
      const payload = await sendResetVerificationCode({
        account: form.account.trim(),
        captcha_id: captcha.challenge_id,
        captcha_code: form.captchaCode.trim(),
      })
      setResetCodeCooldown(Number(payload?.cooldown_seconds) || 60)
      await loadCaptcha('reset')
    } catch (requestError) {
      setError(requestError instanceof Error ? requestError.message : '发送重置验证码失败，请稍后再试。')
      await loadCaptcha('reset')
    } finally {
      setIsSendingResetCode(false)
    }
  }

  function validateSignupStepTwo() {
    if (form.nickname.trim().length < 2) {
      return '昵称至少需要 2 个字符。'
    }
    if (!form.organization.trim()) {
      return '请填写学校或单位。'
    }
    if (!form.agreeTerms) {
      return '请先同意用户协议和隐私政策。'
    }
    return ''
  }

  async function handleSubmit(event) {
    event.preventDefault()
    setError('')

    if (mode === 'login') {
      if (loginStep === 'reset') {
        const resetError = validateResetSubmit()
        if (resetError) {
          setError(resetError)
          return
        }

        setIsLoading(true)
        try {
          const result = await resetPassword({
            account: form.account.trim(),
            verification_code: form.resetVerificationCode.trim(),
            password: form.password,
            confirm_password: form.confirmPassword,
            captcha_id: captcha.challenge_id,
            captcha_code: form.captchaCode.trim(),
          })
          setError(result?.message || '密码重置成功，请登录。')
          setLoginStep('login')
          setForm((currentForm) => ({
            ...buildEmptyForm(),
            account: currentForm.account.trim(),
          }))
          await loadCaptcha('login')
        } catch (requestError) {
          setError(requestError instanceof Error ? requestError.message : '重置密码失败，请稍后再试。')
          await loadCaptcha('reset')
        } finally {
          setIsLoading(false)
        }
        return
      }

      const loginError = validateLogin()
      if (loginError) {
        setError(loginError)
        return
      }

      setIsLoading(true)
      try {
        const authPayload = await loginUser({
          account: form.account.trim(),
          password: form.password,
          captcha_id: captcha.challenge_id,
          captcha_code: form.captchaCode.trim(),
        })
        onAuthSuccess?.(authPayload)
      } catch (requestError) {
        setError(requestError instanceof Error ? requestError.message : '登录失败，请稍后再试。')
        loadCaptcha('login')
      } finally {
        setIsLoading(false)
      }
      return
    }

    if (signupStep === 1) {
      const signupError = validateSignupStepOne()
      if (signupError) {
        setError(signupError)
        return
      }
      setSignupStep(2)
      return
    }

    const signupError = validateSignupStepTwo()
    if (signupError) {
      setError(signupError)
      return
    }

    setIsLoading(true)
    try {
      const authPayload = await registerUser({
        phone: form.phone.trim(),
        phone_verification_code: form.phoneVerificationCode.trim(),
        email: form.email.trim() || null,
        email_verification_code: form.email.trim() ? form.emailVerificationCode.trim() : null,
        password: form.password,
        confirm_password: form.confirmPassword,
        captcha_id: sendCodeCaptcha?.challenge_id || 'verified-by-send-code',
        captcha_code: 'PASS',
        nickname: form.nickname.trim(),
        education: form.education,
        occupation: form.occupation,
        organization: form.organization.trim(),
        discipline: form.discipline,
        agree_terms: form.agreeTerms,
      })
      onAuthSuccess?.(authPayload)
    } catch (requestError) {
      setError(requestError instanceof Error ? requestError.message : '注册失败，请稍后再试。')
      loadCaptcha('register')
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="auth-layout">
      <SendCodeCaptchaModal
        open={sendCodeModal.open}
        title={sendCodeModal.channel === 'email' ? '邮箱发码验证' : '手机发码验证'}
        captcha={sendCodeCaptcha}
        codeValue={sendCodeCaptchaValue}
        isLoading={isSendCodeCaptchaLoading}
        isSubmitting={sendCodeModal.channel === 'email' ? isSendingEmailCode : isSendingPhoneCode}
        onChange={setSendCodeCaptchaValue}
        onRefresh={() => loadSendCodeCaptcha('register')}
        onClose={() => {
          setSendCodeModal({ open: false, channel: '' })
          setSendCodeCaptcha(null)
          setSendCodeCaptchaValue('')
        }}
        onConfirm={handleSendVerificationCode}
      />

      <div className="auth-layout__scene">
        <div className="scene-panel">
          <div className="scene-panel__brand">
            <a href="/" className="scene-brand-link" onClick={(event) => event.preventDefault()}>
              <img
                alt="XK 阅读 logo"
                className="scene-brand-link__logo"
                src={xkLogoIcon}
              />
              <span>XK 阅读</span>
            </a>
          </div>

          <div className="scene-panel__stage">
            <AnimatedCharacters
              activeFieldGroup={activeFieldGroup}
              activePasswordField={activePasswordField}
              isTyping={isTyping}
              showPassword={showPassword}
              showConfirmPassword={showConfirmPassword}
              passwordLength={passwordLength}
            />
          </div>

          <div className="scene-panel__footer">
            <button type="button">隐私政策</button>
            <button type="button">服务条款</button>
          </div>

          <div className="scene-panel__grid" />
          <div className="scene-panel__blur scene-panel__blur--one" />
          <div className="scene-panel__blur scene-panel__blur--two" />
        </div>
      </div>

      <div className="auth-layout__form">
        <div className="auth-card">
          <div className="auth-card__mobile-brand">
            <img
              alt="XK 阅读 logo"
              className="auth-card__mobile-logo"
              src={xkLogoIcon}
            />
            <span>XK 阅读</span>
          </div>

          <div className="auth-card__header">
            <h1>{current.title}</h1>
            <p>{current.description}</p>
          </div>

          {mode === 'signup' ? (
            <div className="auth-steps" aria-label="注册步骤">
              <div className={`auth-step${signupStep === 1 ? ' is-active' : signupStep > 1 ? ' is-done' : ''}`}>
                1. 账号信息
              </div>
              <div className={`auth-step${signupStep === 2 ? ' is-active' : ''}`}>
                2. 基础资料
              </div>
            </div>
          ) : null}

          <form className="auth-form" onSubmit={handleSubmit}>
            {mode === 'login' ? (
              <>
                <div className="auth-form__field">
                  <label htmlFor="account">手机号或邮箱</label>
                  <input
                    id="account"
                    type="text"
                    placeholder="请输入手机号或邮箱"
                    autoComplete="username"
                    value={form.account}
                    onChange={(event) => updateField('account', event.target.value)}
                    onFocus={() => handleFieldFocus('account')}
                    onBlur={handleFieldBlur}
                    className="auth-input"
                  />
                </div>

                {loginStep === 'login' ? (
                  <div className="auth-form__field">
                    <label htmlFor="login-password">密码</label>
                    <div className="auth-input-wrap">
                      <input
                        id="login-password"
                        type={showPassword ? 'text' : 'password'}
                        placeholder="请输入密码"
                        autoComplete="current-password"
                        value={form.password}
                        onChange={(event) => updateField('password', event.target.value)}
                        onFocus={() => handleFieldFocus('password', 'password')}
                        onBlur={handleFieldBlur}
                        className="auth-input auth-input--password"
                      />
                      <button
                        type="button"
                        className="auth-input-wrap__toggle"
                        onClick={() => setShowPassword((value) => !value)}
                      >
                        <EyeIcon hidden={showPassword} />
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <VerificationCodeField
                      id="reset-code"
                      label="重置验证码"
                      placeholder="请输入 6 位重置验证码"
                      value={form.resetVerificationCode}
                      onChange={(value) => updateField('resetVerificationCode', value)}
                      onSend={handleSendResetCode}
                      sending={isSendingResetCode}
                      cooldown={resetCodeCooldown}
                      required
                    />

                    <div className="auth-form__field">
                      <label htmlFor="reset-password">新密码</label>
                      <div className="auth-input-wrap">
                        <input
                          id="reset-password"
                          type={showPassword ? 'text' : 'password'}
                          placeholder="请输入新密码"
                          autoComplete="new-password"
                          value={form.password}
                          onChange={(event) => updateField('password', event.target.value)}
                          onFocus={() => handleFieldFocus('password', 'password')}
                          onBlur={handleFieldBlur}
                          className="auth-input auth-input--password"
                        />
                        <button
                          type="button"
                          className="auth-input-wrap__toggle"
                          onClick={() => setShowPassword((value) => !value)}
                        >
                          <EyeIcon hidden={showPassword} />
                        </button>
                      </div>
                    </div>

                    <div className="auth-form__field">
                      <label htmlFor="reset-confirm-password">确认新密码</label>
                      <div className="auth-input-wrap">
                        <input
                          id="reset-confirm-password"
                          type={showConfirmPassword ? 'text' : 'password'}
                          placeholder="请再次输入新密码"
                          autoComplete="new-password"
                          value={form.confirmPassword}
                          onChange={(event) => updateField('confirmPassword', event.target.value)}
                          onFocus={() => handleFieldFocus('password', 'confirmPassword')}
                          onBlur={handleFieldBlur}
                          className="auth-input auth-input--password"
                        />
                        <button
                          type="button"
                          className="auth-input-wrap__toggle"
                          onClick={() => setShowConfirmPassword((value) => !value)}
                        >
                          <EyeIcon hidden={showConfirmPassword} />
                        </button>
                      </div>
                    </div>
                  </>
                )}

                <CaptchaPanel
                  captcha={captcha}
                  value={form.captchaCode}
                  isLoading={isCaptchaLoading}
                  onChange={(value) => updateField('captchaCode', value)}
                  onRefresh={() => loadCaptcha(loginStep === 'reset' ? 'reset' : 'login')}
                  onFocus={() => handleFieldFocus('account')}
                  onBlur={handleFieldBlur}
                />
              </>
            ) : signupStep === 1 ? (
              <>
                <div className="auth-form__field">
                  <label htmlFor="signup-phone">手机号</label>
                  <input
                    id="signup-phone"
                    type="tel"
                    placeholder="请输入手机号"
                    autoComplete="tel"
                    value={form.phone}
                    onChange={(event) => updateField('phone', event.target.value)}
                    onFocus={() => handleFieldFocus('account')}
                    onBlur={handleFieldBlur}
                    className="auth-input"
                  />
                </div>

                <VerificationCodeField
                  className="auth-form__field--paired"
                  id="signup-phone-code"
                  label="短信验证码"
                  placeholder="请输入 6 位短信验证码"
                  value={form.phoneVerificationCode}
                  onChange={(value) => updateField('phoneVerificationCode', value)}
                  onSend={() => openSendCodeModal('sms')}
                  sending={isSendingPhoneCode}
                  cooldown={phoneCodeCooldown}
                  required
                />

                <div className="auth-form__field">
                  <label htmlFor="signup-email">邮箱</label>
                  <input
                    id="signup-email"
                    type="email"
                    placeholder="可选，填写后需验证"
                    autoComplete="email"
                    value={form.email}
                    onChange={(event) => updateField('email', event.target.value)}
                    onFocus={() => handleFieldFocus('account')}
                    onBlur={handleFieldBlur}
                    className="auth-input"
                  />
                </div>

                <VerificationCodeField
                  className="auth-form__field--paired"
                  id="signup-email-code"
                  label="邮箱验证码"
                  placeholder={form.email.trim() ? '请输入 6 位邮箱验证码' : '填写邮箱后可发送'}
                  value={form.emailVerificationCode}
                  onChange={(value) => updateField('emailVerificationCode', value)}
                  onSend={() => openSendCodeModal('email')}
                  sending={isSendingEmailCode}
                  cooldown={emailCodeCooldown}
                  disabled={!form.email.trim()}
                />

                <div className="auth-form__field">
                  <label htmlFor="signup-password">密码</label>
                  <div className="auth-input-wrap">
                    <input
                      id="signup-password"
                      type={showPassword ? 'text' : 'password'}
                      placeholder="至少 8 位"
                      autoComplete="new-password"
                      value={form.password}
                      onChange={(event) => updateField('password', event.target.value)}
                      onFocus={() => handleFieldFocus('password', 'password')}
                      onBlur={handleFieldBlur}
                      className="auth-input auth-input--password"
                    />
                    <button
                      type="button"
                      className="auth-input-wrap__toggle"
                      onClick={() => setShowPassword((value) => !value)}
                    >
                      <EyeIcon hidden={showPassword} />
                    </button>
                  </div>
                </div>

                <div className="auth-form__field">
                  <label htmlFor="signup-confirm-password">确认密码</label>
                  <div className="auth-input-wrap">
                    <input
                      id="signup-confirm-password"
                      type={showConfirmPassword ? 'text' : 'password'}
                      placeholder="请再次输入密码"
                      autoComplete="new-password"
                      value={form.confirmPassword}
                      onChange={(event) => updateField('confirmPassword', event.target.value)}
                      onFocus={() => handleFieldFocus('password', 'confirmPassword')}
                      onBlur={handleFieldBlur}
                      className="auth-input auth-input--password"
                    />
                    <button
                      type="button"
                      className="auth-input-wrap__toggle"
                      onClick={() => setShowConfirmPassword((value) => !value)}
                    >
                      <EyeIcon hidden={showConfirmPassword} />
                    </button>
                  </div>
                </div>
              </>
            ) : (
              <>
                <div className="auth-form__field">
                  <label htmlFor="nickname">昵称</label>
                  <input
                    id="nickname"
                    type="text"
                    placeholder="请输入昵称"
                    autoComplete="nickname"
                    value={form.nickname}
                    onChange={(event) => updateField('nickname', event.target.value)}
                    onFocus={() => handleFieldFocus('profile')}
                    onBlur={handleFieldBlur}
                    className="auth-input"
                  />
                </div>

                <div className="auth-form__field">
                  <label htmlFor="education">学历</label>
                  <select
                    id="education"
                    value={form.education}
                    onChange={(event) => updateField('education', event.target.value)}
                    onFocus={() => handleFieldFocus('profile')}
                    onBlur={handleFieldBlur}
                    className="auth-input auth-input--select"
                  >
                    {EDUCATION_OPTIONS.map((option) => (
                      <option key={option} value={option}>
                        {option}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="auth-form__field">
                  <label htmlFor="occupation">职业</label>
                  <select
                    id="occupation"
                    value={form.occupation}
                    onChange={(event) => updateField('occupation', event.target.value)}
                    onFocus={() => handleFieldFocus('profile')}
                    onBlur={handleFieldBlur}
                    className="auth-input auth-input--select"
                  >
                    {OCCUPATION_OPTIONS.map((option) => (
                      <option key={option} value={option}>
                        {option}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="auth-form__field">
                  <label htmlFor="organization">学校/单位</label>
                  <input
                    id="organization"
                    type="text"
                    placeholder="请输入学校或单位"
                    autoComplete="organization"
                    value={form.organization}
                    onChange={(event) => updateField('organization', event.target.value)}
                    onFocus={() => handleFieldFocus('profile')}
                    onBlur={handleFieldBlur}
                    className="auth-input"
                  />
                </div>

                <div className="auth-form__field">
                  <label htmlFor="discipline">学科领域</label>
                  <select
                    id="discipline"
                    value={form.discipline}
                    onChange={(event) => updateField('discipline', event.target.value)}
                    onFocus={() => handleFieldFocus('profile')}
                    onBlur={handleFieldBlur}
                    className="auth-input auth-input--select"
                  >
                    {DISCIPLINE_OPTIONS.map((option) => (
                      <option key={option} value={option}>
                        {option}
                      </option>
                    ))}
                  </select>
                </div>

                <label className="auth-checkbox">
                  <input
                    type="checkbox"
                    checked={form.agreeTerms}
                    onChange={(event) => updateField('agreeTerms', event.target.checked)}
                    onFocus={() => handleFieldFocus('agreement')}
                    onBlur={handleFieldBlur}
                  />
                  <span>我已阅读并同意《用户协议》与《隐私政策》</span>
                </label>
              </>
            )}

            {mode === 'login' ? (
              <div className="auth-form__row">
                <label className="remember-row">
                  <input type="checkbox" />
                  <span>30 天内记住我</span>
                </label>
                {loginStep === 'login' ? (
                  <button
                    type="button"
                    className="text-link"
                    onClick={async () => {
                      setLoginStep('reset')
                      setError('')
                      await loadCaptcha('reset')
                    }}
                  >
                    忘记密码？
                  </button>
                ) : (
                  <button
                    type="button"
                    className="text-link"
                    onClick={async () => {
                      setLoginStep('login')
                      setError('')
                      setForm((currentForm) => ({
                        ...buildEmptyForm(),
                        account: currentForm.account,
                      }))
                      await loadCaptcha('login')
                    }}
                  >
                    返回登录
                  </button>
                )}
              </div>
            ) : null}

            {error ? <div className="auth-error">{error}</div> : null}

            <div className="auth-form__actions">
              {mode === 'signup' && signupStep === 2 ? (
                <InteractiveHoverButton
                  type="button"
                  text={copy.signup.back}
                  className="auth-button auth-button--secondary"
                  onClick={() => {
                    setSignupStep(1)
                    setError('')
                  }}
                />
              ) : null}

              <InteractiveHoverButton
                type="submit"
                text={
                  isLoading
                    ? mode === 'login'
                      ? loginStep === 'reset'
                        ? '重置中...'
                        : '登录中...'
                      : '提交中...'
                    : mode === 'signup' && signupStep === 1
                      ? copy.signup.next
                      : mode === 'login' && loginStep === 'reset'
                        ? '重置密码'
                        : current.primary
                }
                className="auth-button auth-button--primary"
                disabled={isLoading}
              />
            </div>
          </form>

          <div className="auth-card__footer">
            {current.footerPrefix}{' '}
            <button
              type="button"
              className="text-link text-link--strong"
              onClick={() => resetForMode(mode === 'login' ? 'signup' : 'login')}
            >
              {current.footerAction}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Login

import { getStoredAuthToken } from './authApi'

function authHeaders() {
  const token = getStoredAuthToken()
  if (!token) return {}
  return { Authorization: `Bearer ${token}` }
}

async function parseJsonResponse(response) {
  let payload = null
  try {
    payload = await response.json()
  } catch {
    payload = null
  }

  if (!response.ok) {
    const detail =
      typeof payload?.detail === 'string'
        ? payload.detail
        : '后台请求失败，请稍后再试。'
    throw new Error(detail)
  }

  return payload
}

export async function fetchAdminOverview() {
  const response = await fetch('/api/admin/overview', {
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function fetchAdminUsers(filters = {}) {
  const query = new URLSearchParams()
  Object.entries(filters || {}).forEach(([key, value]) => {
    if (value !== '' && value !== null && value !== undefined) {
      query.set(key, String(value))
    }
  })
  const response = await fetch(`/api/admin/users${query.toString() ? `?${query.toString()}` : ''}`, {
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function fetchAdminUserDetail(userId) {
  const response = await fetch(`/api/admin/users/${userId}`, {
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function updateAdminUser(userId, payload) {
  const response = await fetch(`/api/admin/users/${userId}`, {
    method: 'PATCH',
    headers: {
      'Content-Type': 'application/json',
      ...authHeaders(),
    },
    body: JSON.stringify(payload),
  })
  return parseJsonResponse(response)
}

export async function uploadAdminUserAvatar(userId, file) {
  const formData = new FormData()
  formData.append('avatar', file)

  const response = await fetch(`/api/admin/users/${userId}/avatar`, {
    method: 'POST',
    headers: {
      ...authHeaders(),
    },
    body: formData,
  })
  return parseJsonResponse(response)
}

export async function fetchAdminPapers() {
  const response = await fetch('/api/admin/papers', {
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function broadcastAdminNotification(payload) {
  const response = await fetch('/api/notifications/broadcast', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      ...authHeaders(),
    },
    body: JSON.stringify(payload),
  })
  return parseJsonResponse(response)
}

import { getStoredAuthToken } from './authApi'

async function parseJsonResponse(response) {
  let payload = null
  try {
    payload = await response.json()
  } catch {
    payload = null
  }

  if (!response.ok) {
    const detail = typeof payload?.detail === 'string' ? payload.detail : '请求失败，请稍后再试。'
    const error = new Error(detail)
    error.status = response.status
    throw error
  }

  return payload
}

function authHeaders() {
  const token = getStoredAuthToken()
  return token ? { Authorization: `Bearer ${token}` } : {}
}

export async function fetchNotificationSummary() {
  const response = await fetch('/api/notifications/summary', {
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function fetchNotifications(limit = 20) {
  const response = await fetch(`/api/notifications?limit=${encodeURIComponent(limit)}`, {
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function markNotificationRead(notificationId) {
  const response = await fetch(`/api/notifications/${notificationId}/read`, {
    method: 'POST',
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function markAllNotificationsRead() {
  const response = await fetch('/api/notifications/read-all', {
    method: 'POST',
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function deleteNotification(notificationId) {
  const response = await fetch(`/api/notifications/${notificationId}`, {
    method: 'DELETE',
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}

export async function clearAllNotifications() {
  const response = await fetch('/api/notifications', {
    method: 'DELETE',
    headers: authHeaders(),
  })
  return parseJsonResponse(response)
}
